class ModelRegistry:
    """Tracks models, training history, and contributions."""

    def __init__(self, metadata_path):
        self.metadata_path = metadata_path
        self.metadata = self._load_metadata()

    def _load_metadata(self):
        if self.metadata_path.exists():
            with open(self.metadata_path, 'r') as f:
                return json.load(f)
        return {
            "models": [],
            "contributions": [],
            "classes": [],
            "total_training_samples": 0,
            "total_contributions": 0
        }

    def save_metadata(self):
        with open(self.metadata_path, 'w') as f:
            json.dump(self.metadata, f, indent=2, default=str)

    def register_model(self, model_id, metrics, num_classes, class_names):
        self.metadata["models"].append({
            "model_id": model_id,
            "created_at": datetime.now().isoformat(),
            "metrics": metrics,
            "num_classes": num_classes,
            "class_names": class_names
        })
        self.metadata["classes"] = class_names
        self.save_metadata()

    def register_contribution(self, contribution_id, contributor, num_samples, label):
        self.metadata["contributions"].append({
            "contribution_id": contribution_id,
            "contributor": contributor,
            "num_samples": num_samples,
            "label": label,
            "submitted_at": datetime.now().isoformat(),
            "status": "pending_review"
        })
        self.metadata["total_contributions"] += num_samples
        self.save_metadata()

    def get_latest_model_id(self):
        if self.metadata["models"]:
            return self.metadata["models"][-1]["model_id"]
        return None

    def approve_contribution(self, contribution_id):
        for c in self.metadata["contributions"]:
            if c["contribution_id"] == contribution_id:
                c["status"] = "approved"
                self.metadata["total_training_samples"] += c["num_samples"]
                self.save_metadata()
                return True
        return False


registry = ModelRegistry(METADATA_FILE)


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def validate_csv_data(df):
    """Validate uploaded CSV has expected structure."""
    errors = []
    if 'image_path' not in df.columns and 'image_data' not in df.columns and 'features' not in df.columns:
        errors.append("CSV must contain 'image_path', 'image_data', or 'features' column.")
    if 'label' not in df.columns:
        errors.append("CSV must contain a 'label' column.")
    if len(df) < 2:
        errors.append("CSV must contain at least 2 samples.")
    if df.isnull().any().any():
        errors.append("CSV contains null values. Please clean data before uploading.")
    return errors


def sanitize_label(label):
    """Sanitize class labels to prevent injection."""
    if not isinstance(label, str):
        label = str(label)
    label = label.strip()
    label = ''.join(c for c in label if c.isalnum() or c in ('_', '-', ' '))
    return label[:100]


def load_and_preprocess_image(image_path, target_size=IMAGE_SIZE):
    """Load an image file and preprocess for model input."""
    try:
        img = Image.open(image_path).convert('RGB')
        img = img.resize(target_size)
        img_array = np.array(img, dtype=np.float32) / 255.0
        return img_array
    except Exception as e:
        logger.error(f"Error loading image {image_path}: {e}")
        return None


def load_csv_training_data(csv_path, base_image_dir=None):
    """Load training data from CSV file.
    
    Supports:
    - CSV with 'image_path' and 'label' columns (paths to image files)
    - CSV with flattened pixel 'features' and 'label' columns
    """
    df = pd.read_csv(csv_path)
    errors = validate_csv_data(df)
    if errors:
        raise ValueError(f"CSV validation errors: {'; '.join(errors)}")

    df['label'] = df['label'].apply(sanitize_label)
    class_names = sorted(df['label'].unique().tolist())
    label_to_index = {name: idx for idx, name in enumerate(class_names)}

    images = []
    labels = []

    if 'image_path' in df.columns:
        for _, row in df.iterrows():
            img_path = row['image_path']
            if base_image_dir:
                img_path = os.path.join(base_image_dir, img_path)

            img_path = os.path.normpath(img_path)
            if '..' in img_path:
                logger.warning(f"Skipping suspicious path: {img_path}")
                continue

            img_array = load_and_preprocess_image(img_path)
            if img_array is not None:
                images.append(img_array)
                labels.append(label_to_index[row['label']])

    elif 'features' in df.columns:
        feature_cols = [c for c in df.columns if c.startswith('feature_') or c == 'features']
        if len(feature_cols) == 1 and feature_cols[0] == 'features':
            for _, row in df.iterrows():
                pixels = np.array(json.loads(row['features']), dtype=np.float32)
                side = int(np.sqrt(len(pixels) / 3))
                if side * side * 3 != len(pixels):
                    side = int(np.sqrt(len(pixels)))
                    img_array = pixels.reshape(side, side, 1)
                else:
                    img_array = pixels.reshape(side, side, 3)
                img_resized = np.array(
                    Image.fromarray((img_array * 255).astype(np.uint8).squeeze()).resize(IMAGE_SIZE).convert('RGB'),
                    dtype=np.float32
                ) / 255.0
                images.append(img_resized)
                labels.append(label_to_index[row['label']])
        else:
            feature_data = df[[c for c in df.columns if c.startswith('feature_')]].values.astype(np.float32)
            for i, row in df.iterrows():
                pixels = feature_data[i]
                side = int(np.sqrt(len(pixels) / 3))
                if side * side * 3 == len(pixels):
                    img_array = pixels.reshape(side, side, 3) / 255.0
                else:
                    side = int(np.sqrt(len(pixels)))
                    img_array = pixels.reshape(side, side, 1) / 255.0
                img_resized = np.array(
                    Image.fromarray((img_array * 255).astype(np.uint8).squeeze()).resize(IMAGE_SIZE).convert('RGB'),
                    dtype=np.float32
                ) / 255.0
                images.append(img_resized)
                labels.append(label_to_index[row['label']])

    if len(images) == 0:
        raise ValueError("No valid training samples could be loaded from CSV.")

    X = np.array(images)
    y = np.array(labels)

    logger.info(f"Loaded {len(X)} samples across {len(class_names)} classes: {class_names}")
    return X, y, class_names


def build_image_classification_model(num_classes, input_shape=(64, 64, 3)):
    """Build a CNN for image classification."""
    model = keras.Sequential([
        layers.Input(shape=input_shape),

        layers.Conv2D(32, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        layers.Conv2D(64, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        layers.Conv2D(128, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        layers.Conv2D(256, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.GlobalAveragePooling2D(),
        layers.Dropout(0.5),

        layers.Dense(256, activation='relu'),
        layers.BatchNormalization(),
        layers.Dropout(0.5),
        layers.Dense(num_classes, activation='softmax')
    ])

    model.compile(
        optimizer=keras.optimizers.Adam(learning_rate=0.001),
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )

    return model


def train_model(X, y, class_names, model_id=None, existing_model_path=None):
    """Train or fine-tune an image classification model."""
    num_classes = len(class_names)
    if model_id is None:
        model_id = f"model_{datetime.now().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}"

    indices = np.random.permutation(len(X))
    X, y = X[indices], y[indices]

    split = int(0.8 * len(X))
    X_train, X_val = X[:split], X[split:]
    y_train, y_val = y[:split], y[split:]

    if existing_model_path and os.path.exists(existing_model_path):
        logger.info(f"Loading existing model from {existing_model_path} for fine-tuning")
        model = keras.models.load_model(existing_model_path)
        if model.output_shape[-1] != num_classes:
            logger.info("Number of classes changed, rebuilding final layer")
            model = build_image_classification_model(num_classes)
    else:
        logger.info("Building new model from scratch")
        model = build_image_classification_model(num_classes)

    logger.info(f"Model summary:")
    model.summary(print_fn=logger.info)

    data_augmentation = keras.Sequential([
        layers.RandomFlip("horizontal"),
        layers.RandomRotation(0.1),
        layers.RandomZoom(0.1),
    ])

    train_dataset = tf.data.Dataset.from_tensor_slices((X_train, y_train))
    train_dataset = train_dataset.shuffle(1000).batch(BATCH_SIZE)
    train_dataset = train_dataset.map(
        lambda x, y_label: (data_augmentation(x, training=True), y_label),
        num_parallel_calls=tf.data.AUTOTUNE
    ).prefetch(tf.data.AUTOTUNE)

    val_dataset = tf.data.Dataset.from_tensor_slices((X_val, y_val))
    val_dataset = val_dataset.batch(BATCH_SIZE).prefetch(tf.data.AUTOTUNE)

    callbacks = [
        keras.callbacks.EarlyStopping(
            monitor='val_loss', patience=5, restore_best_weights=True
        ),
        keras.callbacks.ReduceLROnPlateau(
            monitor='val_loss', factor=0.5, patience=3, min_lr=1e-6
        ),
    ]

    logger.info(f"Starting training with {len(X_train)} train samples, {len(X_val)} val samples")
    history = model.fit(
        train_dataset,
        validation_data=val_dataset,
        epochs=EPOCHS,
        callbacks=callbacks,
        verbose=1
    )

    model_path = MODELS_DIR / model_id
    model.save(str(model_path))

    class_names_path = model_path / "class_names.json"
    with open(class_names_path, 'w') as f:
        json.dump(class_names, f)

    final_metrics = {
        "train_accuracy": float(history.history['accuracy'][-1]),
        "val_accuracy": float(history.history['val_accuracy'][-1]),
        "train_loss": float(history.history['loss'][-1]),
        "val_loss": float(history.history['val_loss'][-1]),
        "epochs_trained": len(history.history['loss']),
        "num_train_samples": len(X_train),
        "num_val_samples": len(X_val),
    }

    registry.register_model(model_id, final_metrics, num_classes, class_names)

    logger.info(f"Model saved: {model_id}, Metrics: {final_metrics}")
    return model_id, final_metrics, history


def load_model_for_prediction(model_id=None):
    """Load a trained model for predictions."""
    if model_id is None:
        model_id = registry.get_latest_model_id()
    if model_id is None:
        return None, None

    model_path = MODELS_DIR / model_id
    if not model_path.exists():
        return None, None

    model = keras.models.load_model(str(model_path))

    class_names_path = model_path / "class_names.json"
    with open(class_names_path, 'r') as f:
        class_names = json.load(f)

    return model, class_names


