@app.route('/api/upload-csv', methods=['POST'])
def upload_csv_and_train():
    """Upload a CSV file with training data and train a model.
    
    Expected CSV format:
    - Column 'image_path': relative path to image files, OR
    - Column 'features': JSON array of pixel values
    - Column 'label': class label string
    
    Optional form fields:
    - 'base_image_dir': base directory for image paths
    - 'retrain': 'true' to fine-tune existing model
    """
    if 'file' not in request.files:
        return jsonify({"error": "No file provided"}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No file selected"}), 400

    if not allowed_file(file.filename):
        return jsonify({"error": "File type not allowed. Use CSV."}), 400

    filename = secure_filename(file.filename)
    upload_id = uuid.uuid4().hex[:12]
    save_path = UPLOAD_DIR / f"{upload_id}_{filename}"
    file.save(str(save_path))

    try:
        base_image_dir = request.form.get('base_image_dir', None)
        retrain = request.form.get('retrain', 'false').lower() == 'true'

        X, y, class_names = load_csv_training_data(str(save_path), base_image_dir)

        existing_model_path = None
        if retrain:
            latest_id = registry.get_latest_model_id()
            if latest_id:
                existing_model_path = str(MODELS_DIR / latest_id)

        model_id, metrics, history = train_model(
            X, y, class_names, existing_model_path=existing_model_path
        )

        return jsonify({
            "status": "success",
            "model_id": model_id,
            "metrics": metrics,
            "class_names": class_names,
            "num_samples": len(X),
            "retrained": retrain
        })

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.exception("Training failed")
        return jsonify({"error": f"Training failed: {str(e)}"}), 500


@app.route('/api/upload-images', methods=['POST'])
def upload_images_and_train():
    """Upload image files with labels and train a model.
    
    Expected: multipart form with image files and a 'labels' JSON field.
    labels format: {"filename1.jpg": "cat", "filename2.jpg": "dog"}
    """
    if 'labels' not in request.form:
        return jsonify({"error": "No labels provided. Include 'labels' as JSON."}), 400

    try:
        labels_map = json.loads(request.form['labels'])
    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON in 'labels' field"}), 400

    files = request.files.getlist('images')
    if not files:
        return jsonify({"error": "No image files provided"}), 400

    upload_id = uuid.uuid4().hex[:12]
    upload_subdir = UPLOAD_DIR / upload_id
    upload_subdir.mkdir(exist_ok=True)

    images = []
    labels = []

    class_names_set = set()
    for fname, label in labels_map.items():
        class_names_set.add(sanitize_label(label))
    class_names = sorted(class_names_set)
    label_to_index = {name: idx for idx, name in enumerate(class_names)}

    for f in files:
        if f.filename and allowed_file(f.filename):
            fname = secure_filename(f.filename)
            fpath = upload_subdir / fname
            f.save(str(fpath))

            if fname in labels_map:
                img_array = load_and_preprocess_image(str(fpath))
                if img_array is not None:
                    label = sanitize_label(labels_map[fname])
                    images.append(img_array)
                    labels.append(label_to_index[label])

    if len(images) < 2:
        return jsonify({"error": "Need at least 2 valid image-label pairs"}), 400

    try:
        X = np.array(images)
        y = np.array(labels)

        retrain = request.form.get('retrain', 'false').lower() == 'true'
        existing_model_path = None
        if retrain:
            latest_id = registry.get_latest_model_id()
            if latest_id:
                existing_model_path = str(MODELS_DIR / latest_id)

        model_id, metrics, history = train_model(
            X, y, class_names, existing_model_path=existing_model_path
        )

        return jsonify({
            "status": "success",
            "model_id": model_id,
            "metrics": metrics,
            "class_names": class_names,
            "num_samples": len(X)
        })
    except Exception as e:
        logger.exception("Training failed")
        return jsonify({"error": f"Training failed: {str(e)}"}), 500


@app.route('/api/contribute', methods=['POST'])
def contribute_training_example():
    """Allow community members to contribute training examples.
    
    Contributions are stored for review before being used in training.
    
    Expected: multipart form with:
    - 'image': image file
    - 'label': class label
    - 'contributor': contributor name/id (optional)
    """
    if 'image' not in request.files:
        return jsonify({"error": "No image file provided"}), 400

    if 'label' not in request.form:
        return jsonify({"error": "No label provided"}), 400

    image_file = request.files['image']
    label = sanitize_label(request.form['label'])
    contributor = request.form.get('contributor', 'anonymous')

    if not image_file.filename or not allowed_file(image_file.filename):
        return jsonify({"error": "Invalid image file"}), 400

    contribution_id = uuid.uuid4().hex[:12]
    label_dir = CONTRIBUTIONS_DIR / label
    label_dir.mkdir(exist_ok=True)

    filename = secure_filename(image_file.filename)
    save_name = f"{contribution_id}_{filename}"
    save_path = label_dir / save_name
    image_file.save(str(save_path))

    # Validate the image can be loaded
    img_array = load_and_preprocess_image(str(save_path))
    if img_array is None:
        os.remove(str(save_path))
        return jsonify({"error": "Could not process image file"}), 400

    registry.register_contribution(contribution_id, contributor, 1, label)

    return jsonify({
        "status": "success",
        "contribution_id": contribution_id,
        "label": label,
        "message": "Thank you for your contribution! It will be reviewed before training."
    })


@app.route('/api/contribute/batch', methods=['POST'])
def contribute_batch():
    """Batch contribute multiple training examples.
    
    Expected: multipart form with:
    - 'images': multiple image files
    - 'labels': JSON mapping filename -> label
    - 'contributor': contributor name/id (optional)
    """
    if 'labels' not in request.form:
        return jsonify({"error": "No labels provided"}), 400

    try:
        labels_map = json.loads(request.form['labels'])
    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON in labels"}), 400

    files = request.files.getlist('images')
    if not files:
        return jsonify({"error": "No image files provided"}), 400

    contributor = request.form.get('contributor', 'anonymous')
    contribution_id = uuid.uuid4().hex[:12]
    saved_count = 0

    for f in files:
        if f.filename and allowed_file(f.filename):
            fname = secure_filename(f.filename)
            if fname in labels_map:
                label = sanitize_label(labels_map[fname])
                label_dir = CONTRIBUTIONS_DIR / label
                label_dir.mkdir(exist_ok=True)

                save_name = f"{contribution_id}_{saved_count}_{fname}"
                save_path = label_dir / save_name
                f.save(str(save_path))

                img_array = load_and_preprocess_image(str(save_path))
                if img_array is not None:
                    saved_count += 1
                else:
                    os.remove(str(save_path))

    if saved_count == 0:
        return jsonify({"error": "No valid contributions could be saved"}), 400

    registry.register_contribution(contribution_id, contributor, saved_count, "batch")

    return jsonify({
        "status": "success",
        "contribution_id": contribution_id,
        "num_saved": saved_count,
        "message": f"Saved {saved_count} contributions for review."
    })


