@app.route('/api/train-with-contributions', methods=['POST'])
def train_with_contributions():
    """Train/retrain model using approved contributions.
    
    Loads all approved contribution images and trains the model.
    """
    images = []
    labels = []
    class_names_set = set()

    # Scan contribution directories
    for label_dir in CONTRIBUTIONS_DIR.iterdir():
        if label_dir.is_dir():
            label = label_dir.name
            class_names_set.add(label)
            for img_file in label_dir.iterdir():
                if img_file.suffix.lower() in {'.png', '.jpg', '.jpeg'}:
                    img_array = load_and_preprocess_image(str(img_file))
                    if img_array is not None:
                        images.append(img_array)
                        labels.append(label)

    if len(images) < 2:
        return jsonify({"error": "Not enough contribution data to train (need at least 2 samples)"}), 400

    class_names = sorted(class_names_set)
    label_to_index = {name: idx for idx, name in enumerate(class_names)}

    X = np.array(images)
    y = np.array([label_to_index[l] for l in labels])

    # Also load any existing training data from previous CSV uploads
    existing_data_files = list(TRAINING_DATA_DIR.glob("*.npz"))
    for npz_file in existing_data_files:
        try:
            data = np.load(str(npz_file))
            X = np.concatenate([X, data['X']])
            y = np.concatenate([y, data['y']])
        except Exception as e:
            logger.warning(f"Could not load existing data {npz_file}: {e}")

    retrain = request.form.get('retrain', 'true').lower() == 'true'
    existing_model_path = None
    if retrain:
        latest_id = registry.get_latest_model_id()
        if latest_id:
            existing_model_path = str(MODELS_DIR / latest_id)

    try:
        model_id, metrics, history = train_model(
            X, y, class_names, existing_model_path=existing_model_path
        )

        # Save combined training data for future use
        combined_path = TRAINING_DATA_DIR / f"combined_{model_id}.npz"
        np.savez(str(combined_path), X=X, y=y)

        return jsonify({
            "status": "success",
            "model_id": model_id,
            "metrics": metrics,
            "class_names": class_names,
            "num_samples": len(X),
            "num_contribution_samples": len(images)
        })
    except Exception as e:
        logger.exception("Training with contributions failed")
        return jsonify({"error": f"Training failed: {str(e)}"}), 500


@app.route('/api/predict', methods=['POST'])
def predict():
    """Predict the class of an uploaded image.
    
    Expected: multipart form with 'image' file.
    Optional: 'model_id' to use a specific model.
    """
    if 'image' not in request.files:
        return jsonify({"error": "No image file provided"}), 400

    image_file = request.files['image']
    if not image_file.filename or not allowed_file(image_file.filename):
        return jsonify({"error": "Invalid image file"}), 400

    model_id = request.form.get('model_id', None)
    model, class_names = load_model_for_prediction(model_id)

    if model is None:
        return jsonify({"error": "No trained model available. Train a model first."}), 404

    with tempfile.NamedTemporaryFile(suffix='.png', delete=False) as tmp:
        image_file.save(tmp.name)
        img_array = load_and_preprocess_image(tmp.name)
        os.unlink(tmp.name)

    if img_array is None:
        return jsonify({"error": "Could not process image"}), 400

    img_batch = np.expand_dims(img_array, axis=0)
    predictions = model.predict(img_batch, verbose=0)
    predicted_class_idx = int(np.argmax(predictions[0]))
    confidence = float(predictions[0][predicted_class_idx])

    all_predictions = {
        class_names[i]: float(predictions[0][i])
        for i in range(len(class_names))
    }

    return jsonify({
        "predicted_class": class_names[predicted_class_idx],
        "confidence": confidence,
        "all_predictions": all_predictions,
        "model_id": model_id or registry.get_latest_model_id()
    })


@app.route('/api/models', methods=['GET'])
def list_models():
    """List all trained models."""
    return jsonify({
        "models": registry.metadata["models"],
        "latest_model": registry.get_latest_model_id()
    })


@app.route('/api/models/<model_id>/download', methods=['GET'])
def download_model(model_id):
    """Download a trained model."""
    model_path = MODELS_DIR / model_id
    if not model_path.exists():
        return jsonify({"error": "Model not found"}), 404

    import shutil
    zip_path = MODELS_DIR / f"{model_id}.zip"
    if not zip_path.exists():
        shutil.make_archive(str(MODELS_DIR / model_id), 'zip', str(model_path))

    return send_file(str(zip_path), as_attachment=True, download_name=f"{model_id}.zip")


@app.route('/api/classes', methods=['GET'])
def get_classes():
    """Get current class names the model recognizes."""
    return jsonify({
        "classes": registry.metadata.get("classes", []),
        "total_training_samples": registry.metadata.get("total_training_samples", 0)
    })


def generate_synthetic_demo_data(num_samples_per_class=50):
    """Generate synthetic demo data for testing the pipeline."""
    class_names = ["circle", "square", "triangle"]
    images = []
    labels = []

    for class_idx, class_name in enumerate(class_names):
        for _ in range(num_samples_per_class):
            img = np.random.rand(IMAGE_SIZE[0], IMAGE_SIZE[1], 3).astype(np.float32) * 0.3

            center_x, center_y = IMAGE_SIZE[0] // 2, IMAGE_SIZE[1] // 2

            if class_name == "circle":
                for x in range(IMAGE_SIZE[0]):
                    for y in range(IMAGE_SIZE[1]):
                        if (x - center_x) ** 2 + (y - center_y) ** 2 < 400:
                            img[x, y, 0] = min(1.0, img[x, y, 0] + 0.6)

            elif class_name == "square":
                img[16:48, 16:48, 1] = np.minimum(1.0, img[16:48, 16:48, 1] + 0.6)

            elif class_name == "triangle":
                for x in range(IMAGE_SIZE[0]):
                    for y in range(IMAGE_SIZE[1]):
                        if y > 16 and y < 48 and x > 16 and x < 48:
                            if x - 16 > abs(y - 32):
                                img[x, y, 2] = min(1.0, img[x, y, 2] + 0.6)

            noise = np.random.rand(IMAGE_SIZE[0], IMAGE_SIZE[1], 3).astype(np.float32) * 0.1
            img = np.clip(img + noise, 0, 1)

            images.append(img)
            labels.append(class_idx)

    return np.array(images), np.array(labels), class_names


@app.route('/api/demo/train', methods=['POST'])
def demo_train():
    """Train a model with synthetic demo data for testing."""
    num_samples = int(request.form.get('num_samples_per_class', 50))
    num_samples = min(num_samples, 200)

    X, y, class_names = generate_synthetic_demo_data(num_samples)

    try:
        model_id, metrics, history = train_model(X, y, class_names)
        return jsonify({
            "status": "success",
            "model_id": model_id,
            "metrics": metrics,
            "class_names": class_names,
            "num_samples": len(X),
            "message": "Demo model trained with synthetic shape data"
        })
    except Exception as e:
        logger.exception("Demo training failed")
        return jsonify({"error": f"Demo training failed: {str(e)}"}), 500


@app.route('/api/demo/generate-csv', methods=['GET'])
def generate_demo_csv():
    """Generate a demo CSV file that can be used for testing the upload endpoint."""
    num_samples = int(request.args.get('num_samples', 30))
    class_names = ["circle", "square", "triangle"]

    rows = []
    for i in range(num_samples):
        label = class_names[i % len(class_names)]
        pixels = np.random.rand(IMAGE_SIZE[0] * IMAGE_SIZE[1] * 3).tolist()
        rows.append({
            "features": json.dumps(pixels),
            "label": label
        })

    df = pd.DataFrame(rows)
    csv_buffer = io.StringIO()
    df.to_csv(csv_buffer, index=False)

    return app.response_class(
        csv_buffer.getvalue(),
        mimetype='text/csv',
        headers={"Content-Disposition": "attachment; filename=demo_training_data.csv"}
    )


